import { Formatter } from '../../formatter.js';
import { createStableId, ensureBlockIdentity } from '../id.js';

const LIST_BULLET_RE = /^\s*(?:[-*•‣▪]|\u2022)\s+(.+)$/;
const LIST_NUMBER_RE = /^\s*(\d+)[.)]\s+(.+)$/;
const HEADING_HINT_RE = /^\s*(subject|to|from|date|re|activities|issues|response|impact|request)\b[:\s]/i;

function clone(value) {
    if (value === undefined) return undefined;
    if (typeof structuredClone === 'function') return structuredClone(value);
    return JSON.parse(JSON.stringify(value));
}

function normalizeText(text) {
    return String(text || '').replace(/\r\n?/g, '\n').replace(/\u00a0/g, ' ');
}

export function sanitizeClipboardHtml(html = '') {
    if (typeof document === 'undefined') return String(html || '');
    const root = document.createElement('div');
    root.innerHTML = String(html || '');
    root.querySelectorAll('script,style,iframe,object,embed,form,input,button,textarea,select,meta,link,svg').forEach(node => node.remove());
    root.querySelectorAll('*').forEach(node => {
        [...node.attributes].forEach(attr => {
            const name = attr.name.toLowerCase();
            const value = String(attr.value || '').trim();
            if (name.startsWith('on')) node.removeAttribute(attr.name);
            else if ((name === 'href' || name === 'src') && /^javascript:/i.test(value)) node.removeAttribute(attr.name);
            else if (name === 'style') node.setAttribute('style', sanitizeStyle(value));
            else if (!['href', 'src', 'alt', 'colspan', 'rowspan', 'style'].includes(name)) node.removeAttribute(attr.name);
        });
    });
    return root.innerHTML;
}

function sanitizeStyle(style) {
    const allowed = new Set(['font-weight', 'font-style', 'text-decoration', 'color', 'background-color', 'text-align']);
    return String(style || '').split(';').map(part => part.trim()).filter(Boolean).filter(part => {
        const [prop, ...rest] = part.split(':');
        const value = rest.join(':').trim();
        return allowed.has(prop.trim().toLowerCase()) && !/url\s*\(|expression\s*\(/i.test(value);
    }).join('; ');
}

function stripFormatting(html) {
    if (typeof document === 'undefined') return Formatter.escapeHtml(Formatter.getPlainTextFromHtml(html));
    const host = document.createElement('div');
    host.innerHTML = html || '';
    return Formatter.plainTextToHtml(host.innerText || host.textContent || '');
}

function classifyPlainTextParagraph(paragraph, index = 0) {
    const trimmed = paragraph.trim();
    const id = createStableId('blk');
    if (!trimmed) return null;
    const headingByPrefix = HEADING_HINT_RE.test(trimmed) && trimmed.length < 120;
    const isTitleLike = index === 0 && trimmed.length < 90 && !/[.!?]$/.test(trimmed);
    return {
        type: 'text',
        style: headingByPrefix || isTitleLike ? 'normal' : 'normal',
        content: Formatter.plainTextToHtml(trimmed),
        preserveWhitespace: false,
        id
    };
}

export function plainTextToRichBlocks(text, options = {}) {
    const raw = normalizeText(text);
    if (!raw.trim()) return [];
    const lines = raw.split('\n');
    const blocks = [];
    let paragraph = [];
    let listBuffer = null;

    const flushParagraph = () => {
        const joined = paragraph.join(' ').replace(/\s+/g, ' ').trim();
        if (joined) {
            const block = classifyPlainTextParagraph(joined, blocks.length);
            if (block) blocks.push(block);
        }
        paragraph = [];
    };

    const flushList = () => {
        if (listBuffer?.items?.length) blocks.push(listBuffer);
        listBuffer = null;
    };

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) {
            flushParagraph();
            flushList();
            if (options.preserveBlankLines) blocks.push({ id: createStableId('blk'), type: 'text', style: 'normal', content: '<br>' });
            continue;
        }
        const bullet = line.match(LIST_BULLET_RE);
        const numbered = line.match(LIST_NUMBER_RE);
        if (bullet || numbered) {
            flushParagraph();
            const type = bullet ? 'ul' : 'ol';
            if (!listBuffer || listBuffer.type !== type) flushList();
            listBuffer ||= { id: createStableId('blk'), type, items: [] };
            listBuffer.items.push({ id: createStableId('item'), text: Formatter.plainTextToHtml((bullet?.[1] || numbered?.[2] || '').trim()), level: Math.max(0, Math.floor((line.match(/^\s*/)?.[0]?.length || 0) / 2)) });
            continue;
        }
        flushList();
        if (paragraph.length && !/^\s/.test(line) && /[.!?:;)]$/.test(paragraph.at(-1) || '')) flushParagraph();
        paragraph.push(trimmed);
    }
    flushParagraph();
    flushList();
    return blocks.map(block => ensureBlockIdentity(block).block);
}

function textOfBlocks(blocks) {
    const scratch = document.createElement('div');
    return (blocks || []).map(block => {
        if (block.type === 'text') { scratch.innerHTML = block.content || ''; return scratch.textContent || ''; }
        if (['ul', 'ol', 'checklist'].includes(block.type)) return (block.items || []).map(item => item.text || '').join('\n');
        if (block.type === 'table') return (block.rows || []).map(row => row.join('\t')).join('\n');
        return '';
    }).join('\n').replace(/\s+/g, ' ').trim();
}

function shouldUsePlainText(htmlBlocks, plainText) {
    const plainBlocks = plainTextToRichBlocks(plainText);
    if (plainBlocks.length <= 1) return false;
    const htmlTextBlocks = (htmlBlocks || []).filter(block => block.type === 'text');
    if (htmlBlocks.length <= 1 && plainBlocks.length > 1) return true;
    if (plainBlocks.length > Math.max(2, htmlTextBlocks.length * 2)) return true;
    const plainTextCollapsed = normalizeText(plainText).replace(/\s+/g, ' ').trim();
    const htmlCollapsed = textOfBlocks(htmlBlocks);
    return htmlTextBlocks.length === 1 && plainTextCollapsed && htmlCollapsed && plainTextCollapsed.replace(/\s/g, '') === htmlCollapsed.replace(/\s/g, '');
}

function normalizeBlock(block, mode) {
    const next = clone(block);
    if (next.type === 'text') {
        next.id ||= createStableId('blk');
        next.style ||= 'normal';
        next.preserveWhitespace = false;
        next.content = mode === 'keep' ? Formatter.normalizeTextBlockHtml(next.content || '', { emptyAsBr: false }) : stripFormatting(next.content || '');
        if (Formatter.isMeaningfullyEmptyHtml(next.content)) return null;
    } else if (['ul', 'ol', 'checklist'].includes(next.type)) {
        next.id ||= createStableId('blk');
        next.items = (next.items || []).map(item => ({ id: item.id || createStableId('item'), level: item.level || 0, checked: !!item.checked, text: mode === 'keep' ? Formatter.normalizeTextBlockHtml(item.text || '', { emptyAsBr: false }) : Formatter.plainTextToHtml(Formatter.getPlainTextFromHtml(item.text || '')) })).filter(item => item.text && !Formatter.isMeaningfullyEmptyHtml(item.text));
        if (!next.items.length) return null;
    } else if (next.type === 'table') {
        next.id ||= createStableId('blk');
        next.rows = (next.rows || []).map(row => row.map(cell => Formatter.escapeHtml(Formatter.normalizeText(cell))));
    }
    return ensureBlockIdentity(next).block;
}

export function normalizeClipboardToBlocks({ html = '', text = '', mode = null } = {}) {
    const preference = mode || localStorage.getItem('openword_paste_mode') || 'match';
    const cleanHtml = html ? sanitizeClipboardHtml(html) : '';
    let htmlBlocks = [];
    if (cleanHtml) htmlBlocks = Formatter.parseHTMLToBlocks(cleanHtml, { plainText: text });
    let blocks = htmlBlocks;
    if (!blocks.length || shouldUsePlainText(blocks, text)) blocks = plainTextToRichBlocks(text);
    if (!blocks.length && text) blocks = plainTextToRichBlocks(text, { preserveBlankLines: false });
    const normalized = blocks.map(block => normalizeBlock(block, preference === 'keep' ? 'keep' : 'match')).filter(Boolean);
    return normalized;
}

