import { getActivePageElement, getPageMetrics, measurePageDom } from './page-metrics.js';

export class LayoutDiagnostics {
    constructor(controller) { this.ctrl = controller; this.panel = null; this.timer = null; }
    setup() {
        window.OpenDocDiagnostics = this;
        document.addEventListener('keydown', event => {
            if ((event.ctrlKey || event.metaKey) && event.altKey && event.key.toLowerCase() === 'd') {
                event.preventDefault();
                this.toggle();
            }
        });
        document.addEventListener('opendoc:performance-sample', () => this.refreshSoon());
    }
    ensurePanel() {
        if (this.panel) return this.panel;
        this.panel = document.createElement('aside');
        this.panel.id = 'layout-diagnostics-panel';
        this.panel.className = 'layout-diagnostics-panel hidden';
        this.panel.innerHTML = '<header><strong>Layout Diagnostics</strong><button type="button" data-action="close">×</button></header><pre></pre>';
        this.panel.querySelector('[data-action="close"]').addEventListener('click', () => this.hide());
        document.body.appendChild(this.panel);
        return this.panel;
    }
    toggle() { this.ensurePanel().classList.toggle('hidden'); this.refresh(); }
    hide() { this.panel?.classList.add('hidden'); }
    refreshSoon() { clearTimeout(this.timer); this.timer = setTimeout(() => this.refresh(), 120); }
    refresh() {
        const panel = this.ensurePanel();
        if (panel.classList.contains('hidden')) return;
        const doc = this.ctrl.state.doc;
        const renderer = this.ctrl.renderer;
        const wrapper = document.getElementById('workspace-wrapper');
        const activePage = getActivePageElement(renderer.container, wrapper);
        const metrics = getPageMetrics(doc.settings || {}, renderer.zoom || 1);
        const pageDom = measurePageDom(activePage, document.querySelector('.ruler-container'));
        const selection = this.ctrl.engine?.captureSelection?.();
        const data = {
            document: { id: doc.id, revision: doc.revision, blocks: doc.blocks?.length || 0 },
            zoom: renderer.zoom,
            pageMetrics: metrics,
            pageDom,
            activeBlockId: this.ctrl.activeBlockId,
            selection,
            pages: renderer.container?.querySelectorAll?.('.page')?.length || 0,
            wrapProxies: document.querySelectorAll('[data-object-wrap-proxy]').length,
            objectLayerInstances: document.querySelectorAll('[data-object-layer-instance="1"]').length,
            serviceWorker: navigator.serviceWorker?.controller?.scriptURL || null,
            performance: window.openDocPerformance?.latest?.(8) || []
        };
        panel.querySelector('pre').textContent = JSON.stringify(data, null, 2);
    }
}

