export const PAGE_SIZES = Object.freeze({
    letter: { widthIn: 8.5, heightIn: 11 },
    a4: { widthIn: 8.27, heightIn: 11.69 },
    legal: { widthIn: 8.5, heightIn: 14 },
    tabloid: { widthIn: 11, heightIn: 17 }
});

export const PX_PER_IN = 96;

export function normalizePageSize(pageSize = 'letter', orientation = 'portrait') {
    const base = PAGE_SIZES[String(pageSize || 'letter').toLowerCase()] || PAGE_SIZES.letter;
    const landscape = orientation === 'landscape';
    return landscape ? { widthIn: base.heightIn, heightIn: base.widthIn } : { ...base };
}

export function normalizeMargins(margins = {}, pageSize = 'letter', orientation = 'portrait') {
    const size = normalizePageSize(pageSize, orientation);
    const maxX = Math.max(0.25, size.widthIn / 2 - 0.1);
    const maxY = Math.max(0.25, size.heightIn / 2 - 0.1);
    const clamp = (value, min, max, fallback) => Math.max(min, Math.min(max, Number.isFinite(Number(value)) ? Number(value) : fallback));
    return {
        top: clamp(margins.top, 0.15, maxY, 1),
        right: clamp(margins.right, 0.15, maxX, 1),
        bottom: clamp(margins.bottom, 0.15, maxY, 1),
        left: clamp(margins.left, 0.15, maxX, 1)
    };
}

export function getPageMetrics(settings = {}, zoom = 1) {
    const orientation = settings.orientation || 'portrait';
    const pageSize = settings.pageSize || 'letter';
    const size = normalizePageSize(pageSize, orientation);
    const margins = normalizeMargins(settings.margins || {}, pageSize, orientation);
    const scale = Math.max(0.05, Number(zoom) || 1);
    const pageWidthPx = size.widthIn * PX_PER_IN;
    const pageHeightPx = size.heightIn * PX_PER_IN;
    const marginLeftPx = margins.left * PX_PER_IN;
    const marginRightPx = margins.right * PX_PER_IN;
    const marginTopPx = margins.top * PX_PER_IN;
    const marginBottomPx = margins.bottom * PX_PER_IN;
    return {
        ...size,
        pageSize,
        orientation,
        margins,
        pxPerIn: PX_PER_IN,
        zoom: scale,
        pageWidthPx,
        pageHeightPx,
        pageWidthScreenPx: pageWidthPx * scale,
        pageHeightScreenPx: pageHeightPx * scale,
        marginLeftPx,
        marginRightPx,
        marginTopPx,
        marginBottomPx,
        contentLeftPx: marginLeftPx,
        contentTopPx: marginTopPx,
        contentWidthPx: Math.max(1, pageWidthPx - marginLeftPx - marginRightPx),
        contentHeightPx: Math.max(1, pageHeightPx - marginTopPx - marginBottomPx)
    };
}

export function getActivePageElement(workspace, viewport = null) {
    const pages = Array.from(workspace?.querySelectorAll?.('.page') || []);
    if (!pages.length) return workspace?.querySelector?.('.mode-pageless') || null;
    const view = viewport || document.getElementById('workspace-wrapper') || document.scrollingElement || document.documentElement;
    const viewRect = view.getBoundingClientRect ? view.getBoundingClientRect() : { top: 0, bottom: window.innerHeight, left: 0, right: window.innerWidth };
    const centerY = (viewRect.top + viewRect.bottom) / 2;
    return pages.sort((a, b) => Math.abs((a.getBoundingClientRect().top + a.getBoundingClientRect().bottom) / 2 - centerY) - Math.abs((b.getBoundingClientRect().top + b.getBoundingClientRect().bottom) / 2 - centerY))[0];
}

export function measurePageDom(page, container = null) {
    const rect = page?.getBoundingClientRect?.();
    const containerRect = container?.getBoundingClientRect?.();
    if (!rect) return null;
    return {
        left: rect.left,
        top: rect.top,
        width: rect.width,
        height: rect.height,
        relativeLeft: containerRect ? rect.left - containerRect.left : rect.left,
        relativeTop: containerRect ? rect.top - containerRect.top : rect.top
    };
}

