import { Formatter } from './formatter.js';
import { normalizeClipboardToBlocks, plainTextToRichBlocks } from './editor/clipboard/paste-normalizer.js';

export class PasteHandler {
    constructor(ctrl) {
        this.ctrl = ctrl;
        this.state = ctrl.state;
    }

    setup() {
        document.addEventListener('paste', (event) => {
            if (event.defaultPrevented) return;
            if (event.target?.tagName === 'INPUT' || event.target?.tagName === 'TEXTAREA') return;
            if (!event.target?.closest?.('#workspace, #workspace-split-wrapper')) return;

            event.preventDefault();
            const html = event.clipboardData?.getData('text/html') || '';
            const text = event.clipboardData?.getData('text/plain') || '';
            if (this.tryPasteUrlOverSelection(text)) return;
            if (this.tryPasteIntoTable(html, text)) return;
            if (this.tryPasteIntoList(html, text)) return;
            this.pasteAsBlocks(html, text);
        });
    }

    isEmptyDocumentBlock(block) {
        if (!block || block.type !== 'text') return false;
        const content = String(block.content || '').trim();
        return content === '' || content === '<br>' || content === 'Start typing...' || Formatter.isMeaningfullyEmptyHtml(content);
    }

    tryPasteUrlOverSelection(text) {
        const raw = String(text || '').trim();
        if (!raw || /\s/.test(raw)) return false;
        let url;
        try {
            url = new URL(raw.match(/^https?:\/\//i) ? raw : `https://${raw}`);
            if (!['http:', 'https:'].includes(url.protocol)) return false;
        } catch (_) { return false; }
        const selection = this.ctrl.engine?.captureSelection?.();
        if (selection?.type !== 'text' || selection.anchor?.blockId !== selection.focus?.blockId || selection.anchor?.offset === selection.focus?.offset) return false;
        this.ctrl.engine.dispatch('createLink', { url: url.href }, { selection });
        return true;
    }

    tryPasteIntoTable(html, text) {
        const selection = this.ctrl.engine?.selection;
        if (selection?.type !== 'table') return false;
        const rows = this.parseTabularText(text) || this.parseHtmlTable(html);
        if (!rows?.length) return false;
        this.ctrl.clipboard?.pasteTable?.({ schemaVersion: 2, selectionType: 'table', table: { rows } });
        return true;
    }

    parseTabularText(text) {
        const lines = String(text || '').replace(/\r\n?/g, '\n').split('\n').filter(line => line.length);
        if (!lines.length || !lines.some(line => line.includes('\t'))) return null;
        return lines.map(line => line.split('\t').map(cell => Formatter.escapeHtml(cell.trim())));
    }

    parseHtmlTable(html) {
        if (!html || typeof document === 'undefined') return null;
        const root = document.createElement('div');
        root.innerHTML = html;
        const table = root.querySelector('table');
        if (!table) return null;
        const rows = [...table.querySelectorAll('tr')].map(tr => [...tr.children].filter(cell => /^(td|th)$/i.test(cell.tagName)).map(cell => Formatter.escapeHtml((cell.innerText || cell.textContent || '').trim()))).filter(row => row.length);
        return rows.length ? rows : null;
    }

    tryPasteIntoList(html, text) {
        const selection = window.getSelection();
        let node = selection?.anchorNode;
        if (node && node.nodeType === Node.TEXT_NODE) node = node.parentElement;
        const li = node?.closest?.('li[data-idx]');
        const listEl = li?.closest?.('ul[data-block-id], ol[data-block-id]');
        if (!li || !listEl) return false;
        const blockId = listEl.dataset.blockId;
        const block = this.state.getBlockById(blockId);
        if (!block || !['ul', 'ol', 'checklist'].includes(block.type)) return false;
        const lines = plainTextToRichBlocks(text || Formatter.getPlainTextFromHtml(html)).flatMap(block => ['ul', 'ol', 'checklist'].includes(block.type) ? block.items.map(item => item.text) : block.type === 'text' ? [block.content] : []);
        if (!lines.length) return false;
        const itemIndex = parseInt(li.dataset.idx, 10);
        const next = JSON.parse(JSON.stringify(block));
        const inserted = lines.map(line => ({ id: Date.now() + Math.random(), text: line, level: next.items[itemIndex]?.level || 0, checked: false }));
        next.items.splice(itemIndex + 1, 0, ...inserted);
        this.state.replaceBlockById(block.id, next, 'paste-list');
        setTimeout(() => this.ctrl.focusListItem(this.state.getBlockIndexById(block.id), itemIndex + inserted.length, 'end'), 0);
        return true;
    }

    pasteAsBlocks(html, text) {
        const blocks = normalizeClipboardToBlocks({ html, text });
        if (!blocks.length) return;
        const selection = this.ctrl.engine?.captureSelection?.();
        if (selection?.type === 'text') {
            this.ctrl.clipboard?.insert?.({ schemaVersion: 2, selectionType: 'text', blocks });
            this.state.signal('PASTE_NORMALIZED', { blockCount: blocks.length });
            return;
        }
        const index = this.ctrl.getInsertBaseIndex();
        blocks.forEach((block, offset) => this.state.insertBlockAt(index + offset + 1, block, 'paste'));
        this.state.notify({ type: 'PASTE_BLOCKS', source: 'paste' });
        setTimeout(() => this.ctrl.focusBlock(Math.min(this.state.doc.blocks.length - 1, index + blocks.length), 'end'), 0);
    }
}

