export class PerformanceMonitor {
    constructor({ enabled = false, thresholdMs = 16 } = {}) {
        this.enabled = enabled || localStorage.getItem('openword_perf_debug') === '1';
        this.thresholdMs = thresholdMs;
        this.samples = [];
    }
    mark(label) {
        if (!this.enabled || typeof performance === 'undefined') return () => undefined;
        const start = performance.now();
        return (extra = {}) => {
            const duration = performance.now() - start;
            const sample = { label, duration, timestamp: Date.now(), ...extra };
            this.samples.push(sample);
            if (this.samples.length > 500) this.samples.shift();
            if (duration >= this.thresholdMs) console.debug(`[OpenDoc perf] ${label}: ${duration.toFixed(1)}ms`, extra);
            document.dispatchEvent(new CustomEvent('opendoc:performance-sample', { detail: sample }));
        };
    }
    latest(count = 30) { return this.samples.slice(-count); }
}

export const openDocPerformance = new PerformanceMonitor();

