import { getPageMetrics, getActivePageElement, measurePageDom } from './layout/page-metrics.js';

export class RulerManager {
    constructor(ctrl) {
        this.ctrl = ctrl;
        this.state = ctrl.state;
        this.renderer = ctrl.renderer;
        this.draggingTab = null;
    }

    setup() {
        this.ensureRulerUi();
        this.attachMarginDrag('marker-margin-left', 'left');
        this.attachMarginDrag('marker-margin-right', 'right');
        this.attachIndentDrag('marker-first-line-indent', 'firstLineIndent');
        this.attachIndentDrag('marker-hanging-indent', 'hangingIndent');
        this.attachTabStopInteraction();
        this.state.subscribe(() => requestAnimationFrame(() => this.sync()));
        document.addEventListener('opendoc:deferred-pagination', () => this.sync());
        window.addEventListener('resize', () => this.sync());
        document.getElementById('workspace-wrapper')?.addEventListener('scroll', () => this.sync(), { passive: true });
        this.sync();
    }

    ensureRulerUi() {
        const ruler = document.getElementById('ruler-bar');
        if (!ruler) return;
        if (!document.getElementById('marker-first-line-indent')) {
            const first = document.createElement('div');
            first.id = 'marker-first-line-indent';
            first.className = 'ruler-marker ruler-indent-marker first-line';
            first.title = 'First-line indent';
            ruler.appendChild(first);
        }
        if (!document.getElementById('marker-hanging-indent')) {
            const hanging = document.createElement('div');
            hanging.id = 'marker-hanging-indent';
            hanging.className = 'ruler-marker ruler-indent-marker hanging';
            hanging.title = 'Hanging indent';
            ruler.appendChild(hanging);
        }
        if (!ruler.querySelector('.ruler-tab-layer')) {
            const layer = document.createElement('div');
            layer.className = 'ruler-tab-layer';
            ruler.appendChild(layer);
        }
    }

    getActiveBlock() {
        const id = this.ctrl.activeBlockId || this.ctrl.engine?.captureSelection?.()?.anchor?.blockId;
        return id ? this.state.getBlockById(id) : null;
    }

    screenDeltaToInches(deltaX, side = 'left') {
        const pxPerIn = this.renderer.pxPerIn || (getPageMetrics(this.state.doc.settings, this.renderer.zoom).pageWidthScreenPx / getPageMetrics(this.state.doc.settings).widthIn);
        const direction = side === 'right' ? -1 : 1;
        return direction * deltaX / Math.max(1, pxPerIn);
    }

    attachMarginDrag(id, side) {
        const el = document.getElementById(id);
        if (!el) return;
        el.onmousedown = (event) => {
            event.preventDefault();
            const startX = event.clientX;
            const startVal = Number(this.state.doc.settings.margins?.[side] || 1);
            const onMove = (moveEvent) => {
                const newVal = startVal + this.screenDeltaToInches(moveEvent.clientX - startX, side);
                this.state.updateMargins(side, newVal);
                this.sync();
            };
            const onUp = () => {
                document.removeEventListener('mousemove', onMove);
                document.removeEventListener('mouseup', onUp);
            };
            document.addEventListener('mousemove', onMove);
            document.addEventListener('mouseup', onUp);
        };
    }

    attachIndentDrag(id, property) {
        const el = document.getElementById(id);
        if (!el) return;
        el.onmousedown = (event) => {
            event.preventDefault();
            const block = this.getActiveBlock();
            if (!block || block.type !== 'text') return;
            const startX = event.clientX;
            const startVal = Number(block[property] || 0);
            const onMove = (moveEvent) => {
                const inches = Math.max(-2, Math.min(6, startVal + this.screenDeltaToInches(moveEvent.clientX - startX, 'left')));
                this.state.updateBlockProps(block.id, { [property]: Math.round(inches * 100) / 100 });
                this.sync();
            };
            const onUp = () => { document.removeEventListener('mousemove', onMove); document.removeEventListener('mouseup', onUp); };
            document.addEventListener('mousemove', onMove);
            document.addEventListener('mouseup', onUp);
        };
    }

    attachTabStopInteraction() {
        const ruler = document.getElementById('ruler-bar');
        if (!ruler) return;
        ruler.addEventListener('dblclick', (event) => {
            if (event.target.classList?.contains('ruler-marker')) return;
            const block = this.getActiveBlock();
            if (!block || block.type !== 'text') return;
            const rect = ruler.getBoundingClientRect();
            const pxPerIn = this.renderer.pxPerIn || 96;
            const xIn = Math.max(0, (event.clientX - rect.left) / pxPerIn);
            const tabStops = Array.isArray(block.tabStops) ? [...block.tabStops] : [];
            tabStops.push({ id: `tab_${Date.now().toString(36)}`, position: Math.round(xIn * 100) / 100, align: 'left' });
            tabStops.sort((a, b) => a.position - b.position);
            this.state.updateBlockProps(block.id, { tabStops });
            this.sync();
        });
    }

    sync() {
        const ruler = document.getElementById('ruler-bar');
        if (!ruler) return;
        const metrics = getPageMetrics(this.state.doc.settings || {}, this.renderer.zoom || 1);
        const activePage = getActivePageElement(this.renderer.container, document.getElementById('workspace-wrapper'));
        const measured = measurePageDom(activePage, ruler.closest('.ruler-container'));
        const pxPerIn = this.renderer.pxPerIn || (measured?.width ? measured.width / metrics.widthIn : metrics.pageWidthScreenPx / metrics.widthIn);
        const margins = this.state.doc.settings.margins || metrics.margins;
        const contentLeft = margins.left * pxPerIn;
        const block = this.getActiveBlock();
        document.getElementById('marker-first-line-indent')?.style.setProperty('left', `${contentLeft + Number(block?.firstLineIndent || 0) * pxPerIn}px`);
        document.getElementById('marker-hanging-indent')?.style.setProperty('left', `${contentLeft + Number(block?.hangingIndent || 0) * pxPerIn}px`);
        this.renderTabStops(block, pxPerIn);
    }

    renderTabStops(block, pxPerIn) {
        const layer = document.querySelector('#ruler-bar .ruler-tab-layer');
        if (!layer) return;
        layer.innerHTML = '';
        const stops = Array.isArray(block?.tabStops) ? block.tabStops : [];
        stops.forEach(stop => {
            const marker = document.createElement('button');
            marker.type = 'button';
            marker.className = 'ruler-tab-stop';
            marker.title = 'Tab stop. Double-click to remove.';
            marker.style.left = `${Number(stop.position || 0) * pxPerIn}px`;
            marker.addEventListener('dblclick', event => {
                event.stopPropagation();
                this.state.updateBlockProps(block.id, { tabStops: stops.filter(item => item.id !== stop.id) });
                this.sync();
            });
            layer.appendChild(marker);
        });
    }
}

