export function getCookie(name) {
    return document.cookie.split(';').map(part => part.trim()).find(part => part.startsWith(`${name}=`))?.slice(name.length + 1) || '';
}

export function installSecurityFetch() {
    if (window.__openwordSecureFetchInstalled) return;
    window.__openwordSecureFetchInstalled = true;
    const nativeFetch = window.fetch.bind(window);
    window.fetch = (input, init = {}) => {
        const method = String(init.method || (input?.method) || 'GET').toUpperCase();
        if (!['GET', 'HEAD', 'OPTIONS'].includes(method)) {
            const headers = new Headers(init.headers || {});
            const token = decodeURIComponent(getCookie('openword_csrf') || '');
            if (token && !headers.has('X-OpenWord-CSRF')) headers.set('X-OpenWord-CSRF', token);
            init = { ...init, headers };
        }
        return nativeFetch(input, init);
    };
}

