export class SidebarManager {
    constructor(ctrl) {
        this.ctrl = ctrl;
        this.state = ctrl.state;
    }

    async refreshDocsList(container = document.getElementById('doc-list')) {
        if (!container) return;
        const list = await this.state.loadDocsList();
        container.innerHTML = '';
        list.forEach((d) => {
            const item = document.createElement('div');
            item.className = `doc-item ${this.state.doc.id === d.id ? 'active' : ''}`;
            item.setAttribute('role', 'button');
            item.tabIndex = 0;
            const details = document.createElement('div');
            details.className = 'doc-item-details';
            const title = document.createElement('div');
            title.className = 'doc-item-title';
            title.textContent = d.title || 'Untitled Document';
            const meta = document.createElement('div');
            meta.className = 'doc-item-meta';
            const updated = d.updatedAt ? new Date(d.updatedAt).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' }) : 'Not saved yet';
            meta.textContent = `${updated}${d.role ? ` · ${d.role}` : ''}`;
            details.append(title, meta);

            const controls = document.createElement('div');
            controls.className = 'doc-item-actions';
            const dup = document.createElement('button');
            dup.className = 'doc-icon-btn';
            dup.title = 'Make a copy';
            dup.setAttribute('aria-label', 'Make a copy');
            dup.innerHTML = '<i data-lucide="copy"></i>';
            dup.onclick = (e) => {
                e.stopPropagation();
                this.state.duplicateDoc(d.id).then(() => this.refreshDocsList(container));
            };
            const del = document.createElement('button');
            del.className = 'doc-icon-btn danger';
            del.title = 'Delete document';
            del.setAttribute('aria-label', 'Delete document');
            del.innerHTML = '<i data-lucide="trash-2"></i>';
            del.onclick = (e) => {
                e.stopPropagation();
                if (confirm(`Delete "${d.title || 'Untitled Document'}"?`)) this.state.deleteDoc(d.id).then(() => this.ctrl.init());
            };
            controls.append(dup, del);
            item.append(details, controls);
            item.onclick = () => { this.state.loadDoc(d.id); document.getElementById('doc-sidebar')?.classList.add('hidden'); };
            item.onkeydown = (event) => { if (event.key === 'Enter' || event.key === ' ') { event.preventDefault(); item.click(); } };
            container.appendChild(item);
        });
        window.lucide?.createIcons?.();
    }

    setup() {
        const ctrl = this.ctrl;
        const sb = document.getElementById('doc-sidebar');
        document.getElementById('btn-docs').onclick = async () => {
            const list = await this.state.loadDocsList();
            const con = document.getElementById('doc-list');
            con.innerHTML = '';
            list.forEach((d) => {
                const item = document.createElement('div');
                item.className = `doc-item ${this.state.doc.id === d.id ? 'active' : ''}`;
                item.setAttribute('role', 'button');
                item.tabIndex = 0;

                const details = document.createElement('div');
                details.className = 'doc-item-details';
                const title = document.createElement('div');
                title.className = 'doc-item-title';
                title.textContent = d.title || 'Untitled Document';
                const meta = document.createElement('div');
                meta.className = 'doc-item-meta';
                const updated = d.updatedAt ? new Date(d.updatedAt).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' }) : 'Not saved yet';
                meta.textContent = `${updated}${d.role ? ` · ${d.role}` : ''}`;
                details.append(title, meta);

                const controls = document.createElement('div');
                controls.className = 'doc-item-actions';

                const dup = document.createElement('button');
                dup.className = 'doc-icon-btn';
                dup.title = 'Make a copy';
                dup.setAttribute('aria-label', 'Make a copy');
                dup.innerHTML = '<i data-lucide="copy"></i>';
                dup.onclick = (e) => {
                    e.stopPropagation();
                    this.state.duplicateDoc(d.id).then(async () => {
                        await this.refreshDocsList(con);
                        this.ctrl.toolbar?.showShellToast?.('Document copied');
                    });
                };

                const del = document.createElement('button');
                del.className = 'doc-icon-btn danger';
                del.title = 'Delete document';
                del.setAttribute('aria-label', 'Delete document');
                del.innerHTML = '<i data-lucide="trash-2"></i>';
                del.onclick = (e) => {
                    e.stopPropagation();
                    if (confirm(`Delete "${d.title || 'Untitled Document'}"?`)) this.state.deleteDoc(d.id).then(() => this.ctrl.init());
                };

                controls.append(dup, del);
                item.append(details, controls);
                item.onclick = () => {
                    this.state.loadDoc(d.id);
                    sb.classList.add('hidden');
                };
                item.onkeydown = (event) => {
                    if (event.key === 'Enter' || event.key === ' ') {
                        event.preventDefault();
                        item.click();
                    }
                };
                con.appendChild(item);
            });
            window.lucide?.createIcons?.();
            sb.classList.remove('hidden');
        };

        document.getElementById('btn-sidebar-close').onclick = () => sb.classList.add('hidden');
        document.getElementById('btn-new-doc').onclick = async () => {
            await this.state.createNewDoc();
            sb.classList.add('hidden');
        };
    }
}

