const CACHE_NAME = 'opendoc-v9-phase51-55-word-features';
const ASSETS = [
  '/',
  '/index.html',
  '/css/variables.css',
  '/css/reset.css',
  '/css/layout.css',
  '/css/typography.css',
  '/css/components.css',
  '/css/shell.css',
  '/css/mobile.css',
  '/css/opendoc-paste-pagination-fixes.css',
  '/main.js',
  '/smart-input-manager.js',
  '/editor/editor-engine.js',
  '/editor/selection-bridge.js',
  '/editor/selection-model.js',
  '/editor/position-mapper.js',
  '/editor/transaction.js',
  '/editor/command-registry.js',
  '/editor/schema.js',
  '/editor/id.js',
  '/security/client-security.js',
  '/performance/performance-monitor.js',
  '/layout/layout-diagnostics.js',
  '/layout/page-metrics.js',
  '/editor/clipboard/paste-normalizer.js',
  '/manifest.json',
];

self.addEventListener('install', (event) => {
  event.waitUntil((async () => {
    const cache = await caches.open(CACHE_NAME);
    await Promise.allSettled(ASSETS.map((asset) => cache.add(asset)));
    await self.skipWaiting();
  })());
});

self.addEventListener('fetch', (event) => {
  if (event.request.method !== 'GET') return;
  if (event.request.url.includes('/api/')) return;
  if (event.request.url.includes('/uploads/')) return;

  const updateCache = (response) => {
    if (response?.ok && response.type === 'basic') {
      caches.open(CACHE_NAME).then((cache) => cache.put(event.request, response.clone()));
    }
    return response;
  };

  // Editor code must not remain pinned to an old implementation after a
  // deployment. Prefer the network for documents, scripts and styles, while
  // keeping a cache fallback for offline use. Other static assets remain
  // cache-first for faster startup.
  if (['document', 'script', 'style', 'worker'].includes(event.request.destination)) {
    event.respondWith(fetch(event.request).then(updateCache).catch(() => caches.match(event.request)));
    return;
  }

  event.respondWith(
    caches.match(event.request).then((cached) => cached || fetch(event.request).then(updateCache))
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil((async () => {
    const keys = await caches.keys();
    await Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key)));
    await self.clients.claim();
  })());
});

