import { defineConfig } from 'vite';

export default defineConfig({
  root: 'public',
  server: {
    proxy: {
      '/api': 'http://localhost:3004',
      '/uploads': 'http://localhost:3004',
    },
    watch: {
      ignored: ['**/uploads/**'],
    },
  },
  build: {
    outDir: 'dist',
    emptyOutDir: true,
  },
});

